// Roll the dice for random numbers every time it runs!
const totalTickets = Math.floor(Math.random() * 25) + 5;   // 5 to 30 tickets
const activeOpen = Math.floor(Math.random() * 8) + 1;      // 1 to 9 open
const criticalOutages = Math.floor(Math.random() * 4);     // 0 to 3 outages
const responseTime = (Math.random() * 20 + 5).toFixed(1);   // 5.0 to 25.0 mins

// Format these random numbers exactly like your original text file
const markdownTemplate = `# DAILY CONTACT CENTER SLA REPORT
- Total Tickets Processed: ${totalTickets}
- Active Open Tickets: ${activeOpen}
- Critical Outages Flagged: ${criticalOutages}
- Average Response Time: ${responseTime} mins`;

// Hand this clean text down to the rest of the factory line
return [{ json: { text: markdownTemplate } }];

// 1. Grab today's mock statistics from your first JavaScript node
const todayText = $('Prepare Today\'s Raw Tickets').item.json.text;

// Helper to extract numbers from your plain text report safely
const extractNumber = (regex, text) => {
  const match = text.match(regex);
  return match ? parseFloat(match[1]) : 0;
};

// Fixed Regex: Stripped out the ** asterisks to match our new clean text format
const processed = extractNumber(/- Total Tickets Processed:\s*(\d+)/i, todayText);
const open = extractNumber(/- Active Open Tickets:\s*(\d+)/i, todayText);
const outages = extractNumber(/- Critical Outages Flagged:\s*(\d+)/i, todayText);
const responseTime = extractNumber(/- Average Response Time:\s*([\d.]+)/i, todayText);

// 2. Grab existing history by decoding the binary file from your renamed node
let history = [];
try {
  // Fixed: Points to 'Fetch Performance History Log' and safely decodes the binary data to text
  const fileContent = $('Fetch Performance History Log').item.binary.data.toText();

  if (fileContent && fileContent.trim()) {
    history = JSON.parse(fileContent);
  }
} catch (e) {
  // If the file was empty, corrupted, or missing, fall back to an empty array
  history = [];
}

// 3. Append today's parsed stats with today's date
history.push({
  date: new Date().toISOString().split('T')[0],
  tickets_processed: processed,
  open_tickets: open,
  outages: outages,
  avg_response_time: responseTime
});

// 4. Limit the file to ONLY keep the last 7 entries (rolling 7-day window)
if (history.length > 7) {
  history.shift();
}

// 5. Return the data structure downstream
return [{
  json: {
    history_json: JSON.stringify(history, null, 2),
    history_raw: history
  }
}];

