// 1. Extract our metrics from the previous node
const rawReport = $('Extract Final Metrics').item.json.final_report;

// Helper to grab numbers from the text report
const getMetric = (regex) => {
  const match = rawReport.match(regex);
  return match ? match[1] : '0';
};

const processed = getMetric(/Total Tickets Processed:\s*(\d+)/);
const open = getMetric(/Active Open Tickets:\s*(\d+)/);
const outages = parseInt(getMetric(/Critical Outages Flagged:\s*(\d+)/) || 0);
const responseTime = getMetric(/Average Response Time:\s*([\d.]+)/);

// 2. Set up our dynamic Obsidian Callouts
let statusCallout = '';
if (outages > 0) {
  statusCallout = `> [!danger] SLA STATUS: CRITICAL OUTAGE 🚨
> **Action Required:** Our daily system check detected an active operational outage.`;
} else {
  statusCallout = `> [!success] SLA STATUS: HEALTHY 🟢
> **All systems nominal.** No critical issues are currently impacting our SLA.`;
}

// 3. Build the beautiful final Markdown
const markdownReport = `# 📊 DAILY CONTACT CENTER SLA REPORT

${statusCallout}

---
### 📈 Today's Performance Metrics
* 📨 **Total Tickets Processed:** \`${processed}\`
* 📂 **Active Open Tickets:** \`${open}\`
* 🚨 **Critical Outages Flagged:** \`${outages}\`
* ⏱️ **Average Response Time:** \`${responseTime} mins\`
`;

return [
  {
    json: {},
    binary: {
      data: {
        data: Buffer.from(markdownReport, 'utf-8').toString('base64'),
        mimeType: 'text/markdown',
        fileName: 'file.md'
      }
    }
  }
];
